// MARK: - Transaction Signing Service

class TransactionSigningService {
    static let shared = TransactionSigningService()
    
    private init() {}
    
    func signTransaction(_ transaction: Transaction, withPrivateKeyData privateKeyData: Data) throws -> Transaction {
        // RLP encode the transaction
        let encodedTx = rlpEncodeTransaction(transaction)
        
        // Hash the encoded transaction
        let txHash = CryptoUtils.keccak256(encodedTx)
        
        // Sign with private key
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: txHash)
        let signatureData = signature.rawRepresentation
        
        var signedTx = transaction
        signedTx.signedData = CryptoUtils.dataToHexString(signatureData)
        signedTx.hash = "0x" + CryptoUtils.dataToHexString(txHash)
        signedTx.status = .signed
        
        return signedTx
    }
    
    private func rlpEncodeTransaction(_ transaction: Transaction) -> Data {
        var encoded = Data()
        
        // Encode nonce
        encoded.append(rlpEncodeUInt64(transaction.nonce))
        
        // Encode gas price
        let gasPriceWei = NSDecimalNumber(decimal: transaction.gasPrice * 1_000_000_000).uint64Value
        encoded.append(rlpEncodeUInt64(gasPriceWei))
        
        // Encode gas limit
        encoded.append(rlpEncodeUInt64(transaction.gasLimit))
        
        // Encode to address
        if let toData = CryptoUtils.hexStringToData(transaction.to) {
            encoded.append(rlpEncodeData(toData))
        }
        
        // Encode value
        let valueWei = NSDecimalNumber(decimal: transaction.amount * Decimal(1e18)).uint64Value
        encoded.append(rlpEncodeUInt64(valueWei))
        
        // Encode empty data field
        encoded.append(rlpEncodeData(Data()))
        
        // Wrap in RLP list
        return rlpEncodeList(encoded)
    }
    
    private func rlpEncodeUInt64(_ value: UInt64) -> Data {
        if value == 0 {
            return Data([0x80])
        }
        var bytes = withUnsafeBytes(of: value.bigEndian) { Data($0) }
        while bytes.first == 0 { bytes.removeFirst() }
        
        if bytes.count == 1 && bytes[0] < 0x80 {
            return bytes
        }
        return Data([0x80 + UInt8(bytes.count)]) + bytes
    }
    
    private func rlpEncodeData(_ data: Data) -> Data {
        if data.count == 1 && data[0] < 0x80 {
            return data
        }
        if data.count <= 55 {
            return Data([0x80 + UInt8(data.count)]) + data
        }
        let lengthBytes = encodeLength(data.count)
        return Data([0xb7 + UInt8(lengthBytes.count)]) + lengthBytes + data
    }
    
    private func rlpEncodeList(_ data: Data) -> Data {
        if data.count <= 55 {
            return Data([0xc0 + UInt8(data.count)]) + data
        }
        let lengthBytes = encodeLength(data.count)
        return Data([0xf7 + UInt8(lengthBytes.count)]) + lengthBytes + data
    }
    
    private func encodeLength(_ length: Int) -> Data {
        var bytes = withUnsafeBytes(of: length.bigEndian) { Data($0) }
        while bytes.first == 0 { bytes.removeFirst() }
        return bytes
    }
}

